define('controller/users/add',['jquery', 'module', 'helpers', 'users'], function ($, module, helpers, users) {
  'use strict';
  return {
    start: function start() {
      var conf = module.config();
      var url = helpers._url('checkLogin', 'Users', 'tao');
      users.checkLogin(conf.loginId, url);
      if (conf.exit === true) {
        setTimeout(function () {
          window.location = helpers._url('index', 'Main', 'tao', {
            structure: 'users',
            ext: 'tao',
            section: 'list_users'
          });
        }, 1000);
      }
    }
  };
});
