define('controller/passwordRecovery',['jquery', 'i18n', 'module', 'ui/feedback', 'layout/version-warning'], function ($, __, module, feedback, versionWarning) {
  'use strict';

  var conf = module.config(),
    feedbackType;
  versionWarning.init();
  if (conf.message) {
    for (feedbackType in conf.message) {
      if (conf.message[feedbackType]) {
        feedback()[feedbackType](conf.message[feedbackType]);
      }
    }
  }
});
