define('controller/WebHooks/edit',['jquery', 'i18n', 'layout/loading-bar', 'ui/hider', 'tao/provider/authSelector', 'tpl!tao/controller/WebHooks/tpl/authContainer'], function ($, __, loadingBar, hider, authSelectorProvider, authContainerTpl) {
  'use strict';
  function getAuthContainer() {
    var $propertyContainer = $('.content-block .wh-auth-container');
    if ($propertyContainer.length) {
      return $propertyContainer;
    }
    $propertyContainer = $(authContainerTpl());
    $('.content-block input[name="classUri"][value="http_2_www_0_tao_0_lu_1_Ontologies_1_TAO_0_rdf_3_WebHook"]').before($propertyContainer);
    return $propertyContainer;
  }
  return {
    start: function start() {
      var $container = getAuthContainer();
      var $elId = $('.content-block input[name="classUri"][value="http_2_www_0_tao_0_lu_1_Ontologies_1_TAO_0_rdf_3_WebHook"]').siblings('#uri');
      var params = {};
      if ($elId.length) {
        params = {
          uri: $elId.val()
        };
      }
      function toggleFields($fields, enabled) {
        if (enabled) {
          $fields.removeAttr('disabled').removeProp('disabled');
        } else {
          $fields.attr('disabled', true).prop('disabled', true);
        }
      }
      function showAuthFormPart() {
        var $allForms = $container.find('.wh-auth-form-part');
        var $selectedForm = $container.find('[data-auth-method="' + this.value + '"]');
        hider.hide($allForms);
        hider.show($selectedForm);
        toggleFields($allForms.find(':input'), false);
        toggleFields($selectedForm.find(':input'), true);
      }
      loadingBar.start();
      authSelectorProvider.getHtml(params).then(function (html) {
        $container.html(html);
        $container.find('.wh-auth-type-selector').each(showAuthFormPart).on('change', showAuthFormPart);
      }).catch(function () {
        throw new Error(__('WebHook auth configuration can not be loaded'));
      }).then(function () {
        loadingBar.stop();
      });
    }
  };
});
